Lecture Notes AWS Infrastructure Data Centers Each data center can host tens of thousands of servers. AWS builds and manages its own custom hardware for efficiency and reliability. Availability Zone (AZ) One or more physically separate data centers within a Region. Each AZ is designed for fault isolation. Connected via low-latency, high-throughput private links. AWS recommends deploying workloads across at least two AZs. Region A Region contains at least three Availability Zones. There are currently 25+ Regions worldwide. Regions are interconnected by the AWS backbone network. Most services are Region-scoped by default. Edge Locations Global network of edge sites designed to serve content with minimal latency. Used by services such as: Amazon CloudFront (CDN) AWS WAF (Web Application Firewall) Amazon Route 53 (DNS Service) Hands-On Labs Lab 01 – AWS Account &amp; IAM Setup Create an AWS Account → 01-01 Configure Virtual MFA Device → 01-02 Create Admin Group and Admin User → 01-03 Account Authentication Support → 01-04

Tổng quan Trong module này, bạn sẽ xây dựng quy trình duyệt admin hoàn chỉnh cho nền tảng Thư Viện Online. Bạn sẽ triển khai kiểm soát truy cập dựa trên vai trò sử dụng Cognito User Groups, tạo các hàm Lambda cho logic phê duyệt/từ chối, và xây dựng giao diện bảng điều khiển admin.
Thời gian thực hiện: ~90 phút
Các dịch vụ sử dụng:
Amazon Cognito (User Groups) AWS Lambda (logic phê duyệt/từ chối) Amazon S3 (các thao tác file) Amazon DynamoDB (cập nhật trạng thái) Amazon API Gateway (các endpoint admin) Những gì bạn sẽ học được Cấu hình Cognito User Groups cho kiểm soát dựa trên vai trò Triển khai các hàm Lambda chỉ dành cho admin Xây dựng các thao tác sao chép file giữa các thư mục S3 Cập nhật trạng thái DynamoDB với quy trình phê duyệt Tạo giao diện bảng điều khiển admin với các điều khiển phê duyệt Triển khai ghi nhật ký audit cho tính minh bạch Kiến trúc cho module này Người dùng Admin → Bảng điều khiển → API Gateway → Lambda (approveBook/rejectBook) ↓ Kiểm tra vai trò Admin (JWT) ↓ Sao chép S3: uploads/ → public/books/ ↓ Cập nhật DynamoDB (APPROVED/REJECTED) ↓ Ghi vào CloudWatch Bước 1: Cấu hình Cognito User Groups 1.1 Tạo nhóm Admin qua CDK Cập nhật lib/online-library-cdk-stack.ts:
// đường dẫn: lib/online-library-cdk-stack.ts import * as cognito from &#39;aws-cdk-lib/aws-cognito&#39;; export class OnlineLibraryCdkStack extends cdk.Stack { constructor(scope: Construct, id: string, props?: cdk.StackProps) { super(scope, id, props); // ...mã Cognito User Pool hiện có... // Tạo nhóm Admin const adminGroup = new cognito.CfnUserPoolGroup(this, &#39;AdminGroup&#39;, { userPoolId: userPool.userPoolId, groupName: &#39;Admins&#39;, description: &#39;Người dùng quản trị viên có quyền phê duyệt&#39;, precedence: 1, }); // Tạo nhóm Người dùng (tùy chọn, để rõ ràng hơn) const usersGroup = new cognito.CfnUserPoolGroup(this, &#39;UsersGroup&#39;, { userPoolId: userPool.userPoolId, groupName: &#39;Users&#39;, description: &#39;Người dùng thông thường có quyền tải lên&#39;, precedence: 10, }); // Xuất tên nhóm new cdk.CfnOutput(this, &#39;AdminGroupName&#39;, { value: adminGroup.groupName!, exportName: &#39;OnlineLibraryAdminGroup&#39;, }); } } 1.2 Thêm người dùng vào nhóm Admin Qua AWS CLI:
# Thêm người dùng vào nhóm Admins aws cognito-idp admin-add-user-to-group \ --user-pool-id YOUR_USER_POOL_ID \ --username admin@example.com \ --group-name Admins # Xác minh tư cách thành viên nhóm aws cognito-idp admin-list-groups-for-user \ --user-pool-id YOUR_USER_POOL_ID \ --username admin@example.com Bước 2: Tạo các hàm Lambda phê duyệt 2.1 Tạo hàm Lambda approveBook Tạo lambda/approveBook/index.py:
# đường dẫn: lambda/approveBook/index.py import json import boto3 from datetime import datetime import os s3_client = boto3.client(&#39;s3&#39;) dynamodb = boto3.resource(&#39;dynamodb&#39;) UPLOADS_BUCKET = os.environ[&#39;UPLOADS_BUCKET&#39;] BOOKS_BUCKET = os.environ[&#39;BOOKS_BUCKET&#39;] BOOKS_TABLE = os.environ[&#39;BOOKS_TABLE&#39;] table = dynamodb.Table(BOOKS_TABLE) def lambda_handler(event, context): &#34;&#34;&#34; Phê duyệt tải sách lên và di chuyển đến thư mục công khai &#34;&#34;&#34; try: # Xác thực vai trò admin claims = event[&#39;requestContext&#39;][&#39;authorizer&#39;][&#39;jwt&#39;][&#39;claims&#39;] groups = claims.get(&#39;cognito:groups&#39;, &#39;&#39;).split(&#39;,&#39;) if &#39;Admins&#39; not in groups: return { &#39;statusCode&#39;: 403, &#39;body&#39;: json.dumps({ &#39;error&#39;: &#39;Cấm truy cập: Cần quyền admin&#39; }) } # Phân tích request body = json.loads(event[&#39;body&#39;]) book_id = body.get(&#39;bookId&#39;) approval_notes = body.get(&#39;notes&#39;, &#39;&#39;) if not book_id: return { &#39;statusCode&#39;: 400, &#39;body&#39;: json.dumps({ &#39;error&#39;: &#39;Thiếu bookId&#39; }) } # Lấy metadata sách từ DynamoDB response = table.get_item( Key={ &#39;bookId&#39;: book_id, &#39;version&#39;: 1 } ) if &#39;Item&#39; not in response: return { &#39;statusCode&#39;: 404, &#39;body&#39;: json.dumps({ &#39;error&#39;: &#39;Sách không tồn tại&#39; }) } book = response[&#39;Item&#39;] # Kiểm tra trạng thái sách if book[&#39;status&#39;] != &#39;PENDING&#39;: return { &#39;statusCode&#39;: 400, &#39;body&#39;: json.dumps({ &#39;error&#39;: f&#39;Trạng thái sách là {book[&#34;status&#34;]}, không phải PENDING&#39; }) } # Sao chép file từ uploads/ sang public/books/ source_key = book[&#39;s3Key&#39;] # ví dụ: pending/book-id.pdf file_extension = source_key.split(&#39;.&#39;)[-1] destination_key = f&#34;public/books/{book_id}.{file_extension}&#34; # Sao chép đối tượng s3_client.copy_object( CopySource={ &#39;Bucket&#39;: UPLOADS_BUCKET, &#39;Key&#39;: source_key }, Bucket&#39;: BOOKS_BUCKET, Key&#39;: destination_key ) # Xóa bản gốc trong uploads/ s3_client.delete_object( Bucket=UPLOADS_BUCKET, Key=source_key ) # Cập nhật DynamoDB admin_id = claims[&#39;sub&#39;] admin_email = claims.get(&#39;email&#39;, &#39;unknown&#39;) approval_timestamp = datetime.utcnow().isoformat() table.update_item( Key={ &#39;bookId&#39;: book_id, &#39;version&#39;: 1 }, UpdateExpression=&#39;&#39;&#39; SET #status = :status, approvedBy = :admin_id, approverEmail = :admin_email, approvalTimestamp = :timestamp, approvalNotes = :notes, publicS3Key = :public_key, publicBucket = :public_bucket &#39;&#39;&#39;, ExpressionAttributeNames={ &#39;#status&#39;: &#39;status&#39; }, ExpressionAttributeValues={ &#39;:status&#39;: &#39;APPROVED&#39;, &#39;:admin_id&#39;: admin_id, &#39;:admin_email&#39;: admin_email, &#39;:timestamp&#39;: approval_timestamp, &#39;:notes&#39;: approval_notes, &#39;:public_key&#39;: destination_key, &#39;:public_bucket&#39;: BOOKS_BUCKET } ) return { &#39;statusCode&#39;: 200, &#39;headers&#39;: { &#39;Content-Type&#39;: &#39;application/json&#39;, &#39;Access-Control-Allow-Origin&#39;: &#39;*&#39;, }, &#39;body&#39;: json.dumps({ &#39;message&#39;: &#39;Phê duyệt sách thành công&#39;, &#39;bookId&#39;: book_id, &#39;approvedBy&#39;: admin_email, &#39;timestamp&#39;: approval_timestamp }) } except Exception as e: print(f&#34;Error: {str(e)}&#34;) return { &#39;statusCode&#39;: 500, &#39;body&#39;: json.dumps({ &#39;error&#39;: &#39;Lỗi máy chủ nội bộ&#39; }) } 2.2 Tạo hàm Lambda rejectBook Tạo lambda/rejectBook/index.py:
# đường dẫn: lambda/rejectBook/index.py import json import boto3 from datetime import datetime import os s3_client = boto3.client(&#39;s3&#39;) dynamodb = boto3.resource(&#39;dynamodb&#39;) UPLOADS_BUCKET = os.environ[&#39;UPLOADS_BUCKET&#39;] BOOKS_TABLE = os.environ[&#39;BOOKS_TABLE&#39;] table = dynamodb.Table(BOOKS_TABLE) def lambda_handler(event, context): &#34;&#34;&#34; Từ chối tải sách lên với lý do &#34;&#34;&#34; try: # Xác thực vai trò admin claims = event[&#39;requestContext&#39;][&#39;authorizer&#39;][&#39;jwt&#39;][&#39;claims&#39;] groups = claims.get(&#39;cognito:groups&#39;, &#39;&#39;).split(&#39;,&#39;) if &#39;Admins&#39; not in groups: return { &#39;statusCode&#39;: 403, &#39;body&#39;: json.dumps({ &#39;error&#39;: &#39;Cấm truy cập: Cần quyền admin&#39; }) } # Phân tích request body = json.loads(event[&#39;body&#39;]) book_id = body.get(&#39;bookId&#39;) rejection_reason = body.get(&#39;reason&#39;, &#39;Không có lý do được cung cấp&#39;) rejection_category = body.get(&#39;category&#39;, &#39;other&#39;) if not book_id: return { &#39;statusCode&#39;: 400, &#39;body&#39;: json.dumps({ &#39;error&#39;: &#39;Thiếu bookId&#39; }) } # Xác thực danh mục từ chối valid_categories = [&#39;copyright&#39;, &#39;inappropriate&#39;, &#39;quality&#39;, &#39;format&#39;, &#39;other&#39;] if rejection_category not in valid_categories: rejection_category = &#39;other&#39; # Lấy metadata sách response = table.get_item( Key={ &#39;bookId&#39;: book_id, &#39;version&#39;: 1 } ) if &#39;Item&#39; not in response: return { &#39;statusCode&#39;: 404, &#39;body&#39;: json.dumps({ &#39;error&#39;: &#39;Sách không tồn tại&#39; }) } book = response[&#39;Item&#39;] # Kiểm tra trạng thái sách if book[&#39;status&#39;] != &#39;PENDING&#39;: return { &#39;statusCode&#39;: 400, &#39;body&#39;: json.dumps({ &#39;error&#39;: f&#39;Trạng thái sách là {book[&#34;status&#34;]}, không phải PENDING&#39; }) } # Tùy chọn: Di chuyển sang khu vực cách ly thay vì xóa source_key = book[&#39;s3Key&#39;] quarantine_key = source_key.replace(&#39;pending/&#39;, &#39;quarantine/&#39;) s3_client.copy_object( CopySource={ &#39;Bucket&#39;: UPLOADS_BUCKET, &#39;Key&#39;: source_key }, Bucket=UPLOADS_BUCKET, Key=quarantine_key ) # Xóa bản gốc s3_client.delete_object( Bucket=UPLOADS_BUCKET, Key=source_key ) # Cập nhật DynamoDB admin_id = claims[&#39;sub&#39;] admin_email = claims.get(&#39;email&#39;, &#39;unknown&#39;) rejection_timestamp = datetime.utcnow().isoformat() table.update_item( Key={ &#39;bookId&#39;: book_id, &#39;version&#39;: 1 }, UpdateExpression=&#39;&#39;&#39; SET #status = :status, rejectedBy = :admin_id, rejectorEmail = :admin_email, rejectionTimestamp = :timestamp, rejectionReason = :reason, rejectionCategory = :category, quarantineS3Key = :quarantine_key &#39;&#39;&#39;, ExpressionAttributeNames={ &#39;#status&#39;: &#39;status&#39; }, ExpressionAttributeValues={ &#39;:status&#39;: &#39;REJECTED&#39;, &#39;:admin_id&#39;: admin_id, &#39;:admin_email&#39;: admin_email, &#39;:timestamp&#39;: rejection_timestamp, &#39;:reason&#39;: rejection_reason, &#39;:category&#39;: rejection_category, &#39;:quarantine_key&#39;: quarantine_key } ) return { &#39;statusCode&#39;: 200, &#39;headers&#39;: { &#39;Content-Type&#39;: &#39;application/json&#39;, &#39;Access-Control-Allow-Origin&#39;: &#39;*&#39;, }, &#39;body&#39;: json.dumps({ &#39;message&#39;: &#39;Sách đã bị từ chối thành công&#39;, &#39;bookId&#39;: book_id, &#39;rejectedBy&#39;: admin_email, &#39;reason&#39;: rejection_reason, &#39;timestamp&#39;: rejection_timestamp }) } except Exception as e: print(f&#34;Error: {str(e)}&#34;) return { &#39;statusCode&#39;: 500, &#39;body&#39;: json.dumps({ &#39;error&#39;: &#39;Lỗi máy chủ nội bộ&#39; }) } 2.3 Thêm các hàm Lambda vào CDK Stack // đường dẫn: lib/online-library-cdk-stack.ts // ...mã hiện có... // Tạo hàm Lambda phê duyệt const approveBookFunction = new lambda.Function(this, &#39;ApproveBook&#39;, { runtime: lambda.Runtime.PYTHON_3_9, handler: &#39;index.lambda_handler&#39;, code: lambda.Code.fromAsset(&#39;lambda/approveBook&#39;), environment: { UPLOADS_BUCKET: uploadsBucket.bucketName, BOOKS_BUCKET: booksBucket.bucketName, BOOKS_TABLE: booksTable.tableName, }, timeout: cdk.Duration.seconds(30), }); // Cấp quyền uploadsBucket.grantRead(approveBookFunction); uploadsBucket.grantDelete(approveBookFunction); booksBucket.grantPut(approveBookFunction); booksTable.grantReadWriteData(approveBookFunction); // Tạo hàm Lambda từ chối const rejectBookFunction = new lambda.Function(this, &#39;RejectBook&#39;, { runtime: lambda.Runtime.PYTHON_3_9, handler: &#39;index.lambda_handler&#39;, code: lambda.Code.fromAsset(&#39;lambda/rejectBook&#39;), environment: { UPLOADS_BUCKET: uploadsBucket.bucketName, BOOKS_TABLE: booksTable.tableName, }, timeout: cdk.Duration.seconds(30), }); // Cấp quyền uploadsBucket.grantReadWrite(rejectBookFunction); booksTable.grantReadWriteData(rejectBookFunction); // Thêm các route httpApi.addRoutes({ path: &#39;/admin/approve&#39;, methods: [apigateway.HttpMethod.POST], integration: new integrations.HttpLambdaIntegration( &#39;ApproveBookIntegration&#39;, approveBookFunction ), authorizer: jwtAuthorizer, }); httpApi.addRoutes({ path: &#39;/admin/reject&#39;, methods: [apigateway.HttpMethod.POST], integration: new integrations.HttpLambdaIntegration( &#39;RejectBookIntegration&#39;, rejectBookFunction ), authorizer: jwtAuthorizer, }); Bước 3: Xây dựng giao diện bảng điều khiển Admin 3.1 Tạo Client API Admin Tạo src/lib/api/admin.ts:
// đường dẫn: src/lib/api/admin.ts import { fetchAuthSession } from &#39;aws-amplify/auth&#39;; export interface PendingBook { bookId: string; title: string; author: string; description?: string; fileSize: number; fileType: string; uploadTimestamp: string; uploaderEmail: string; status: string; } export async function getPendingBooks(): Promise&lt;PendingBook[]&gt; { const session = await fetchAuthSession(); const idToken = session.tokens?.idToken?.toString(); const response = await fetch(`${process.env.NEXT_PUBLIC_API_URL}/admin/pending`, { headers: { &#39;Authorization&#39;: `Bearer ${idToken}`, }, }); if (!response.ok) { throw new Error(&#39;Failed to fetch pending books&#39;); } return response.json(); } export async function approveBook(bookId: string, notes?: string): Promise&lt;void&gt; { const session = await fetchAuthSession(); const idToken = session.tokens?.idToken?.toString(); const response = await fetch(`${process.env.NEXT_PUBLIC_API_URL}/admin/approve`, { method: &#39;POST&#39;, headers: { &#39;Content-Type&#39;: &#39;application/json&#39;, &#39;Authorization&#39;: `Bearer ${idToken}`, }, body: JSON.stringify({ bookId, notes }), }); if (!response.ok) { const error = await response.json(); throw new Error(error.error || &#39;Failed to approve book&#39;); } } export async function rejectBook( bookId: string, reason: string, category: string ): Promise&lt;void&gt; { const session = await fetchAuthSession(); const idToken = session.tokens?.idToken?.toString(); const response = await fetch(`${process.env.NEXT_PUBLIC_API_URL}/admin/reject`, { method: &#39;POST&#39;, headers: { &#39;Content-Type&#39;: &#39;application/json&#39;, &#39;Authorization&#39;: `Bearer ${idToken}`, }, body: JSON.dumps({ bookId, reason, category }), }); if (!response.ok) { const error = await response.json(); throw new Error(error.error || &#39;Failed to reject book&#39;); } } 3.2 Tạo Component Bảng điều khiển Admin Tạo src/components/admin/PendingBooksList.tsx:
// đường dẫn: src/components/admin/PendingBooksList.tsx &#39;use client&#39;; import { useState, useEffect } from &#39;react&#39;; import { getPendingBooks, approveBook, rejectBook, PendingBook } from &#39;@/lib/api/admin&#39;; export function PendingBooksList() { const [books, setBooks] = useState&lt;PendingBook[]&gt;([]); const [loading, setLoading] = useState(true); const [selectedBook, setSelectedBook] = useState&lt;PendingBook | null&gt;(null); const [action, setAction] = useState&lt;&#39;approve&#39; | &#39;reject&#39; | null&gt;(null); const [rejectionReason, setRejectionReason] = useState(&#39;&#39;); const [rejectionCategory, setRejectionCategory] = useState(&#39;other&#39;); const [approvalNotes, setApprovalNotes] = useState(&#39;&#39;); const [processing, setProcessing] = useState(false); useEffect(() =&gt; { loadPendingBooks(); }, []); const loadPendingBooks = async () =&gt; { try { const data = await getPendingBooks(); setBooks(data); } catch (error) { console.error(&#39;Error loading pending books:&#39;, error); } finally { setLoading(false); } }; const handleApprove = async () =&gt; { if (!selectedBook) return; setProcessing(true); try { await approveBook(selectedBook.bookId, approvalNotes); setBooks(books.filter(b =&gt; b.bookId !== selectedBook.bookId)); setSelectedBook(null); setAction(null); setApprovalNotes(&#39;&#39;); } catch (error) { alert(&#39;Failed to approve book: &#39; + error); } finally { setProcessing(false); } }; const handleReject = async () =&gt; { if (!selectedBook || !rejectionReason) return; setProcessing(true); try { await rejectBook(selectedBook.bookId, rejectionReason, rejectionCategory); setBooks(books.filter(b =&gt; b.bookId !== selectedBook.bookId)); setSelectedBook(null); setAction(null); setRejectionReason(&#39;&#39;); } catch (error) { alert(&#39;Failed to reject book: &#39; + error); } finally { setProcessing(false); } }; if (loading) { return &lt;div className=&#34;text-center py-8&#34;&gt;Đang tải danh sách sách chờ duyệt...&lt;/div&gt;; } return ( &lt;div className=&#34;space-y-6&#34;&gt; &lt;h2 className=&#34;text-2xl font-bold&#34;&gt;Sách Chờ Duyệt ({books.length})&lt;/h2&gt; {books.length === 0 ? ( &lt;p className=&#34;text-gray-600&#34;&gt;Không có sách nào chờ duyệt&lt;/p&gt; ) : ( &lt;div className=&#34;grid gap-4&#34;&gt; {books.map((book) =&gt; ( &lt;div key={book.bookId} className=&#34;border rounded-lg p-4 bg-white shadow&#34;&gt; &lt;div className=&#34;flex justify-between items-start&#34;&gt; &lt;div className=&#34;flex-1&#34;&gt; &lt;h3 className=&#34;font-semibold text-lg&#34;&gt;{book.title}&lt;/h3&gt; &lt;p className=&#34;text-gray-600&#34;&gt;tác giả {book.author}&lt;/p&gt; {book.description &amp;&amp; ( &lt;p className=&#34;text-sm text-gray-500 mt-2&#34;&gt;{book.description}&lt;/p&gt; )} &lt;div className=&#34;mt-2 text-sm text-gray-500&#34;&gt; &lt;p&gt;Người tải lên: {book.uploaderEmail}&lt;/p&gt; &lt;p&gt;Kích thước: {(book.fileSize / 1024 / 1024).toFixed(2)} MB&lt;/p&gt; &lt;p&gt;Ngày tải lên: {new Date(book.uploadTimestamp).toLocaleString()}&lt;/p&gt; &lt;/div&gt; &lt;/div&gt; &lt;div className=&#34;flex gap-2 ml-4&#34;&gt; &lt;button onClick={() =&gt; { setSelectedBook(book); setAction(&#39;approve&#39;); }} className=&#34;px-4 py-2 bg-green-600 text-white rounded hover:bg-green-700&#34; &gt; Duyệt &lt;/button&gt; &lt;button onClick={() =&gt; { setSelectedBook(book); setAction(&#39;reject&#39;); }} className=&#34;px-4 py-2 bg-red-600 text-white rounded hover:bg-red-700&#34; &gt; Từ chối &lt;/button&gt; &lt;/div&gt; &lt;/div&gt; &lt;/div&gt; ))} &lt;/div&gt; )} {/* Approval Modal */} {action === &#39;approve&#39; &amp;&amp; selectedBook &amp;&amp; ( &lt;div className=&#34;fixed inset-0 bg-black bg-opacity-50 flex items-center justify-center p-4&#34;&gt; &lt;div className=&#34;bg-white rounded-lg p-6 max-w-md w-full&#34;&gt; &lt;h3 className=&#34;text-xl font-bold mb-4&#34;&gt;Phê duyệt Sách&lt;/h3&gt; &lt;p className=&#34;mb-4&#34;&gt; Bạn có chắc chắn muốn phê duyệt &#34;{selectedBook.title}&#34; không? &lt;/p&gt; &lt;div className=&#34;mb-4&#34;&gt; &lt;label className=&#34;block text-sm font-medium mb-2&#34;&gt; Ghi chú phê duyệt (tùy chọn) &lt;/label&gt; &lt;textarea value={approvalNotes} onChange={(e) =&gt; setApprovalNotes(e.target.value)} className=&#34;w-full px-3 py-2 border rounded&#34; rows={3} placeholder=&#34;Thêm bất kỳ ghi chú nào về phê duyệt này...&#34; /&gt; &lt;/div&gt; &lt;div className=&#34;flex gap-2&#34;&gt; &lt;button onClick={handleApprove} disabled={processing} className=&#34;flex-1 px-4 py-2 bg-green-600 text-white rounded hover:bg-green-700 disabled:bg-gray-300&#34; &gt; {processing ? &#39;Đang xử lý...&#39; : &#39;Xác nhận phê duyệt&#39;} &lt;/button&gt; &lt;button onClick={() =&gt; { setAction(null); setSelectedBook(null); setApprovalNotes(&#39;&#39;); }} disabled={processing} className=&#34;px-4 py-2 border rounded hover:bg-gray-100&#34; &gt; Hủy &lt;/button&gt; &lt;/div&gt; &lt;/div&gt; &lt;/div&gt; )} {/* Rejection Modal */} {action === &#39;reject&#39; &amp;&amp; selectedBook &amp;&amp; ( &lt;div className=&#34;fixed inset-0 bg-black bg-opacity-50 flex items-center justify-center p-4&#34;&gt; &lt;div className=&#34;bg-white rounded-lg p-6 max-w-md w-full&#34;&gt; &lt;h3 className=&#34;text-xl font-bold mb-4&#34;&gt;Từ chối Sách&lt;/h3&gt; &lt;p className=&#34;mb-4&#34;&gt; Vui lòng cung cấp lý do từ chối cho &#34;{selectedBook.title}&#34;: &lt;/p&gt; &lt;div className=&#34;mb-4&#34;&gt; &lt;label className=&#34;block text-sm font-medium mb-2&#34;&gt;Danh mục&lt;/label&gt; &lt;select value={rejectionCategory} onChange={(e) =&gt; setRejectionCategory(e.target.value)} className=&#34;w-full px-3 py-2 border rounded&#34; &gt; &lt;option value=&#34;copyright&#34;&gt;Vấn đề bản quyền&lt;/option&gt; &lt;option value=&#34;inappropriate&#34;&gt;Nội dung không phù hợp&lt;/option&gt; &lt;option value=&#34;quality&#34;&gt;Chất lượng kém&lt;/option&gt; &lt;option value=&#34;format&#34;&gt;Định dạng không hợp lệ&lt;/option&gt; &lt;option value=&#34;other&#34;&gt;Khác&lt;/option&gt; &lt;/select&gt; &lt;/div&gt; &lt;div className=&#34;mb-4&#34;&gt; &lt;label className=&#34;block text-sm font-medium mb-2&#34;&gt;Lý do *&lt;/label&gt; &lt;textarea value={rejectionReason} onChange={(e) =&gt; setRejectionReason(e.target.value)} className=&#34;w-full px-3 py-2 border rounded&#34; rows={4} placeholder=&#34;Giải thích lý do từ chối sách này...&#34; required /&gt; &lt;/div&gt; &lt;div className=&#34;flex gap-2&#34;&gt; &lt;button onClick={handleReject} disabled={processing || !rejectionReason} className=&#34;flex-1 px-4 py-2 bg-red-600 text-white rounded hover:bg-red-700 disabled:bg-gray-300&#34; &gt; {processing ? &#39;Đang xử lý...&#39; : &#39;Xác nhận từ chối&#39;} &lt;/button&gt; &lt;button onClick={() =&gt; { setAction(null); setSelectedBook(null); setRejectionReason(&#39;&#39;); }} disabled={processing} className=&#34;px-4 py-2 border rounded hover:bg-gray-100&#34; &gt; Hủy &lt;/button&gt; &lt;/div&gt; &lt;/div&gt; &lt;/div&gt; )} &lt;/div&gt; ); } Xác minh &amp; Kiểm thử Danh sách kiểm tra Nhóm Admin trong Cognito được tạo và người dùng được gán Lambda phê duyệt sao chép file chính xác Lambda từ chối di chuyển file vào khu vực cách ly DynamoDB cập nhật đúng trạng thái và metadata Bảng điều khiển admin hiển thị sách chờ duyệt Modal phê duyệt hoạt động và cập nhật UI Modal từ chối yêu cầu lý do Người dùng không phải admin không truy cập được các endpoint admin Các vấn đề thường gặp &amp; Giải pháp Vấn đề: JWT không chứa claim cognito:groups
